#Requires -RunAsAdministrator
<#
.SYNOPSIS
  Удаляет Frontol 6 (текущий) и ставит указанный дистрибутив 6.25.x.
  Базу C:\БД Frontol\ НЕ удаляет.

.EXAMPLE
  .\Install-Frontol625.ps1 -InstallerPath "D:\Distr\Frontol_6.25.1_Full.exe"
#>
param(
    [Parameter(Mandatory = $true)]
    [string]$InstallerPath,

    [string]$UninstallerPath = "${env:ProgramFiles(x86)}\ATOL\UninstallFrontol6.exe",

    [string]$DbPath = "C:\БД Frontol",

    # Тихие ключи InstallShield / ATOL часто такие; если установщик ругнётся — убери SilentArgs
    [string]$SilentArgs = "/s /sms"
)

$ErrorActionPreference = "Stop"

function Write-Step([string]$Message) {
    Write-Host ""
    Write-Host "==> $Message" -ForegroundColor Cyan
}

if (-not (Test-Path -LiteralPath $InstallerPath)) {
    throw "Не найден установщик: $InstallerPath"
}

if (-not (Test-Path -LiteralPath $DbPath)) {
    Write-Warning "Папка базы не найдена: $DbPath (продолжение всё равно)"
}
else {
    Write-Host "База сохраняется: $DbPath" -ForegroundColor Green
    Get-ChildItem -LiteralPath $DbPath -Filter *.GDB -ErrorAction SilentlyContinue |
        ForEach-Object { Write-Host "  - $($_.Name) ($([math]::Round($_.Length/1MB,1)) MB)" }
}

Write-Step "Остановка служб Frontol / Firebird (если есть)"
$serviceNames = @(
    "FrontolService",
    "Frontol*",
    "FirebirdServerDefaultInstance",
    "FirebirdServer*"
)
Get-Service -ErrorAction SilentlyContinue |
    Where-Object {
        $_.Name -like "Frontol*" -or
        $_.DisplayName -like "Frontol*" -or
        $_.Name -like "Firebird*" -or
        $_.DisplayName -like "Firebird*"
    } |
    ForEach-Object {
        try {
            if ($_.Status -ne "Stopped") {
                Write-Host "Stop: $($_.Name)"
                Stop-Service -Name $_.Name -Force -ErrorAction Stop
            }
        }
        catch {
            Write-Warning "Не удалось остановить $($_.Name): $($_.Exception.Message)"
        }
    }

Get-Process -Name "Frontol","FrontolIni","FrontolService","FrontolAdmin*" -ErrorAction SilentlyContinue |
    ForEach-Object {
        Write-Host "Kill: $($_.ProcessName) ($($_.Id))"
        Stop-Process -Id $_.Id -Force -ErrorAction SilentlyContinue
    }

Write-Step "Удаление текущего Frontol 6"
if (Test-Path -LiteralPath $UninstallerPath) {
    Write-Host "Запуск: $UninstallerPath"
    # У разных сборок тихий режим отличается; сначала пробуем /S
    $uninstall = Start-Process -FilePath $UninstallerPath -ArgumentList "/S" -Wait -PassThru
    if ($uninstall.ExitCode -ne 0) {
        Write-Warning "Тихое удаление вернуло код $($uninstall.ExitCode). Пробуем без ключей (может открыться GUI)..."
        Start-Process -FilePath $UninstallerPath -Wait
    }
}
else {
    Write-Warning "UninstallFrontol6.exe не найден: $UninstallerPath"
    Write-Warning "Пробуем удаление через реестр Uninstall..."
    $uninstallKeys = @(
        "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*",
        "HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*"
    )
    $apps = Get-ItemProperty $uninstallKeys -ErrorAction SilentlyContinue |
        Where-Object { $_.DisplayName -match "Frontol\s*6" }
    if (-not $apps) {
        Write-Warning "Запись Frontol 6 в Uninstall не найдена — возможно уже удалён."
    }
    else {
        foreach ($app in $apps) {
            Write-Host "Найдено: $($app.DisplayName)"
            if ($app.UninstallString) {
                Write-Host "UninstallString: $($app.UninstallString)"
                # Часто это InstallShield — запускаем как есть
                cmd /c "$($app.UninstallString)"
            }
        }
    }
}

Start-Sleep -Seconds 3

Write-Step "Установка Frontol из: $InstallerPath"
Write-Host "Аргументы: $SilentArgs"
$install = Start-Process -FilePath $InstallerPath -ArgumentList $SilentArgs -Wait -PassThru
Write-Host "Код выхода установщика: $($install.ExitCode)"

if ($install.ExitCode -ne 0) {
    Write-Warning "Тихая установка могла не пройти. Запускаю установщик с GUI..."
    Start-Process -FilePath $InstallerPath -Wait
}

Write-Step "Готово"
Write-Host @"

Дальше вручную:
1) Запусти FrontolIni.exe
2) Каталог: C:\БД Frontol\
3) По умолчанию (MAIN.GDB / LOG.GDB / SYSDBA / masterkey)
4) Проверить -> Применить
5) Запусти Frontol

"@ -ForegroundColor Yellow

#Requires -RunAsAdministrator
<#
.SYNOPSIS
  Удаляет текущий Frontol 6 и ставит 6.25.x из локального файла
  ИЛИ по прямой ссылке, которую ты сам возьмёшь из кабинета АТОЛ.

  Автоматически «найти и скачать» Frontol с официального сайта без логина НЕВОЗМОЖНО.
  Левые зеркала в скрипт НЕ зашиты специально.

.EXAMPLE
  # У тебя уже есть файл:
  .\Install-Frontol625.ps1 -InstallerPath "D:\Frontol_6_25_1_Full.exe"

.EXAMPLE
  # Прямая ссылка из личного кабинета / Download Center АТОЛ:
  .\Install-Frontol625.ps1 -DownloadUrl "https://..../Frontol_6_25_1_Full.exe"
#>
param(
    [string]$InstallerPath = "",

    [string]$DownloadUrl = "",

    [string]$DownloadDir = "C:\Temp\FrontolSetup",

    [string]$UninstallerPath = "${env:ProgramFiles(x86)}\ATOL\UninstallFrontol6.exe",

    [string]$DbPath = "C:\БД Frontol",

    [string]$SilentArgs = "/s /sms",

    # Поиск установщика на дисках/шарах (имена 6.25*)
    [string[]]$SearchRoots = @(
        "C:\",
        "D:\",
        "\\localhost\share"
    )
)

$ErrorActionPreference = "Stop"

function Write-Step([string]$Message) {
    Write-Host ""
    Write-Host "==> $Message" -ForegroundColor Cyan
}

function Find-LocalInstaller {
    Write-Step "Поиск локального установщика Frontol 6.25*"
    $patterns = @(
        "Frontol*6*25*.exe",
        "Frontol_6_25*.exe",
        "Frontol*6.25*.exe"
    )

    foreach ($root in $SearchRoots) {
        if (-not (Test-Path -LiteralPath $root)) { continue }
        Write-Host "Ищу в: $root"
        foreach ($pattern in $patterns) {
            try {
                $hit = Get-ChildItem -LiteralPath $root -Filter $pattern -Recurse -ErrorAction SilentlyContinue |
                    Where-Object { $_.Length -gt 50MB } |
                    Sort-Object LastWriteTime -Descending |
                    Select-Object -First 1
                if ($hit) { return $hit.FullName }
            }
            catch { }
        }
    }
    return $null
}

Write-Host @"

Frontol — коммерческий продукт АТОЛ.
Официальная загрузка: https://frontol.ru/resources/Download_Center/
или портал/ЛК АТОЛ (нужен логин).

Этот скрипт НЕ качает с неизвестных зеркал.

"@ -ForegroundColor Yellow

if (-not (Test-Path -LiteralPath $DbPath)) {
    Write-Warning "Папка базы не найдена: $DbPath"
}
else {
    Write-Host "База НЕ удаляется: $DbPath" -ForegroundColor Green
}

# 1) Определяем установщик
if (-not $InstallerPath -and $DownloadUrl) {
    New-Item -ItemType Directory -Path $DownloadDir -Force | Out-Null
    $InstallerPath = Join-Path $DownloadDir ([IO.Path]::GetFileName(($DownloadUrl -split "\?")[0]))
    if (-not $InstallerPath.EndsWith(".exe")) {
        $InstallerPath = Join-Path $DownloadDir "Frontol_6_25_Full.exe"
    }
    Write-Step "Скачивание по твоей ссылке"
    Write-Host $DownloadUrl
    Write-Host "-> $InstallerPath"
    Invoke-WebRequest -Uri $DownloadUrl -OutFile $InstallerPath -UseBasicParsing
}

if (-not $InstallerPath) {
    $InstallerPath = Find-LocalInstaller
}

if (-not $InstallerPath -or -not (Test-Path -LiteralPath $InstallerPath)) {
    Write-Host @"

Установщик 6.25 не найден.

Что сделать:
1) Зайди в кабинет АТОЛ / Download Center
2) Скачай Frontol_6_25_x_Full.exe (лучше 6.25.1 под твою БД)
3) Запусти снова:

   .\Install-Frontol625.ps1 -InstallerPath "C:\путь\Frontol_6_25_1_Full.exe"

Или если есть прямая URL из кабинета:

   .\Install-Frontol625.ps1 -DownloadUrl "https://.../Frontol_6_25_1_Full.exe"

Альтернатива без 6.25: скопируй установщик со СТАРОЙ кассы
(Downloads, папка дистрибутивов, флешка, общая шара).

"@ -ForegroundColor Red
    exit 1
}

Write-Host "Установщик: $InstallerPath" -ForegroundColor Green

Write-Step "Остановка Frontol / Firebird"
Get-Service -ErrorAction SilentlyContinue |
    Where-Object {
        $_.Name -like "Frontol*" -or $_.DisplayName -like "Frontol*" -or
        $_.Name -like "Firebird*" -or $_.DisplayName -like "Firebird*"
    } |
    ForEach-Object {
        try {
            if ($_.Status -ne "Stopped") {
                Write-Host "Stop: $($_.Name)"
                Stop-Service -Name $_.Name -Force -ErrorAction Stop
            }
        }
        catch {
            Write-Warning "Не удалось остановить $($_.Name): $($_.Exception.Message)"
        }
    }

Get-Process -Name "Frontol","FrontolIni","FrontolService" -ErrorAction SilentlyContinue |
    ForEach-Object {
        Write-Host "Kill: $($_.ProcessName)"
        Stop-Process -Id $_.Id -Force -ErrorAction SilentlyContinue
    }

Write-Step "Удаление текущего Frontol 6"
if (Test-Path -LiteralPath $UninstallerPath) {
    $u = Start-Process -FilePath $UninstallerPath -ArgumentList "/S" -Wait -PassThru
    if ($u.ExitCode -ne 0) {
        Write-Warning "Тихое удаление: код $($u.ExitCode). Запуск GUI..."
        Start-Process -FilePath $UninstallerPath -Wait
    }
}
else {
    Write-Warning "Не найден: $UninstallerPath — пропускаю удаление или удали вручную."
}

Start-Sleep -Seconds 3

Write-Step "Установка"
$i = Start-Process -FilePath $InstallerPath -ArgumentList $SilentArgs -Wait -PassThru
Write-Host "Код выхода: $($i.ExitCode)"
if ($i.ExitCode -ne 0) {
    Write-Warning "Тихая установка не прошла — GUI..."
    Start-Process -FilePath $InstallerPath -Wait
}

Write-Step "Готово"
Write-Host @"

Дальше:
1) FrontolIni.exe
2) Каталог: C:\БД Frontol\
3) По умолчанию -> Проверить -> Применить
4) Запуск Frontol

"@ -ForegroundColor Yellow
